func TestBuildInboundPlanCreateBodyFromCSV(t *testing.T) {
	dir := t.TempDir()
	addressPath := filepath.Join(dir, "address.json")
	itemsPath := filepath.Join(dir, "items.csv")
	if err := os.WriteFile(addressPath, []byte(`{"name":"Warehouse","addressLine1":"1 Main","city":"Austin","countryCode":"US","postalCode":"78701","stateOrProvinceCode":"TX"}`), 0o600); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(itemsPath, []byte("msku,quantity,prepOwner,labelOwner,expiration,manufacturingLotCode\nSKU-1,12,SELLER,SELLER,2026-12-31,LOT-7\n"), 0o600); err != nil {
		t.Fatal(err)
	}

	req, err := buildInboundPlanCreateBody(inboundPlanCreateOptions{
		marketplaceID: "ATVPDKIKX0DER",
		sourceAddress: addressPath,
		items:         itemsPath,
		name:          "June FBA",
	}, strings.NewReader(""))
	if err != nil {
		t.Fatal(err)
	}
	if len(req.warnings) != 0 {
		t.Fatalf("unexpected warnings: %v", req.warnings)
	}
	body := req.body.(map[string]any)
	if got := body["name"]; got != "June FBA" {
		t.Fatalf("name = %v", got)
	}
	items := body["items"].([]map[string]any)
	if len(items) != 1 {
		t.Fatalf("items len = %d", len(items))
	}
	if items[0]["msku"] != "SKU-1" || items[0]["quantity"] != 12 || items[0]["manufacturingLotCode"] != "LOT-7" {
		t.Fatalf("unexpected item: %#v", items[0])
	}
}

