func runInboundCLI(args ...string) (string, string, error) {
	root := RootCmd()
	var stdout bytes.Buffer
	var stderr bytes.Buffer
	root.SetOut(&stdout)
	root.SetErr(&stderr)
	root.SetArgs(args)
	err := root.Execute()
	time.Sleep(0)
	return stdout.String(), stderr.String(), err
}
